    <script>
        document.getElementById('filter-form').addEventListener('submit', async function(event) {
            event.preventDefault();
            const jobType = document.getElementById('job-type').value;
            const resultDiv = document.getElementById('result');
            resultDiv.innerHTML = '';

            try {
                const response = await fetch('/jobs', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({ job_type: jobType })
                });
                if (response.ok) {
                    const data = await response.json();
                    if (data.length === 0) {
                        resultDiv.innerHTML = '<div class="alert alert-warning" role="alert">No jobs found</div>';
                    } else {
                        let jobsTable = `
                            <table class="table table-bordered mt-4">
                                <thead>
                                    <tr>
                                        <th>ID</th>
                                        <th>Name</th>
                                        <th>Type</th>
                                        <th>Description</th>
                                    </tr>
                                </thead>
                                <tbody>
                        `;
                        data.forEach(user => {
                            jobsTable += `
                                <tr>
                                    <td>${user.id}</td>
                                    <td>${user.name}</td>
                                    <td>${user.type}</td>
                                    <td>${user.description}</td>
                                </tr>
                            `;
                        });
                        jobsTable += '</tbody></table>';
                        resultDiv.innerHTML = jobsTable;
                    }
                } else {
                    const errorData = await response.json();
                    resultDiv.innerHTML = `
                        <div class="alert alert-danger" role="alert">
                            Error: ${errorData.detail}
                        </div>
                    `;
                }
            } catch (error) {
                resultDiv.innerHTML = `
                    <div class="alert alert-danger" role="alert">
                        Network error or server is down.
                    </div>
                `;
            }
        });
    </script>
</body>
